     * @throws ClientException If the API returns a client error response
     * @throws ServerException If the API returns a server error response
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun oBPv300CreateViewForBankAccount(bankid: kotlin.String, accountid: kotlin.String, obPv600CreateCustomViewManagementRequest: OBPv600CreateCustomViewManagementRequest) : OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead {
        val localVarResponse = oBPv300CreateViewForBankAccountWithHttpInfo(bankid = bankid, accountid = accountid, obPv600CreateCustomViewManagementRequest = obPv600CreateCustomViewManagementRequest)

        return when (localVarResponse.responseType) {
            ResponseType.Success -> (localVarResponse as Success<*>).data as OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead
            ResponseType.Informational -> throw UnsupportedOperationException("Client does not support Informational responses.")
            ResponseType.Redirection -> throw UnsupportedOperationException("Client does not support Redirection responses.")
            ResponseType.ClientError -> {
                val localVarError = localVarResponse as ClientError<*>
                throw ClientException("Client error : ${localVarError.statusCode} ${localVarError.message.orEmpty()}", localVarError.statusCode, localVarResponse)
            }
            ResponseType.ServerError -> {
                val localVarError = localVarResponse as ServerError<*>
                throw ServerException("Server error : ${localVarError.statusCode} ${localVarError.message.orEmpty()} ${localVarError.body}", localVarError.statusCode, localVarResponse)
            }
        }
    }

