     * @return ApiResponse<OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead?>
     * @throws IllegalStateException If the request is not correctly configured
     * @throws IOException Rethrows the OkHttp execute method exception
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class)
    fun oBPv300UpdateViewForBankAccountWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, obPv300UpdateViewForBankAccountRequest: OBPv300UpdateViewForBankAccountRequest) : ApiResponse<OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead?> {
        val localVariableConfig = oBPv300UpdateViewForBankAccountRequestConfig(bankid = bankid, accountid = accountid, viewid = viewid, obPv300UpdateViewForBankAccountRequest = obPv300UpdateViewForBankAccountRequest)

