    fun oBPv510GrantUserAccessToViewById(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, obPv510RevokeUserAccessToViewByIdRequest: OBPv510RevokeUserAccessToViewByIdRequest) : OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead {
